import{_ as i,a as l,b as r}from"./chunks/DriverUpdateSuccessfully.Cjcb7A7z.js";import{_ as o,o as a,c as t,a3 as n}from"./chunks/framework.DXXx-gl1.js";const f=JSON.parse('{"title":"Download and install drivers","description":"","frontmatter":{},"headers":[],"relativePath":"InstallationGuides/InstallDrivers.md","filePath":"InstallationGuides/InstallDrivers.md","lastUpdated":1772558338000}'),s={name:"InstallationGuides/InstallDrivers.md"};function d(c,e,p,u,h,m){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="download-and-install-drivers" tabindex="-1">Download and install drivers <a class="header-anchor" href="#download-and-install-drivers" aria-label="Permalink to &quot;Download and install drivers&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Considering to SecureBoot and StableRelease, some devices&#39; DriverPacks(e.g. XiaomiPad5, Xiaomi9) are released by their maintainer, Please read their official installation guide. Here explains a generic way to install drivers from GIT repository.</p></div><h2 id="preparation" tabindex="-1">Preparation <a class="header-anchor" href="#preparation" aria-label="Permalink to &quot;Preparation&quot;">​</a></h2><ul><li><p>Download <a href="https://github.com/WOA-Project/DriverUpdater/releases" target="_blank" rel="noreferrer">DriverUpdater</a> by <a href="https://github.com/WOA-Project/" target="_blank" rel="noreferrer">WOA-Project</a></p><blockquote><p>Generally speaking please download the x64/x86 one, if <strong>Your Computer</strong> has more than one x86 CPU.</p></blockquote></li><li><p>Download Driver Pack</p><blockquote><p>Just click the Download Button in the page. <img src="'+i+'" width="40%/"></p></blockquote><ul><li>For Sm8150 Devices, the repo is <a href="https://github.com/Project-Aloha/msmnile-Drivers" target="_blank" rel="noreferrer">msmnile-Drivers</a></li><li>For Sm7125 Devices, the repo is <a href="https://github.com/Project-Aloha/Atoll-Drivers" target="_blank" rel="noreferrer">Atoll-Drivers</a></li><li>For others, please refer to <a href="./../ReferenceTables/QCSiliconCodenameReferenceTable.html">QC Silicons&#39; Codename Reference Table</a><br> and download the one named xxx-Drivers.</li></ul></li><li><p>Download Device Specific Driver Pack</p><blockquote><p>Just click the Download Zip Button to Download. <img src="'+l+'" width="40%/"></p></blockquote><ul><li>For Xiaomi Pad 5, the repo is <a href="https://github.com/remtrik-stuff/MiPad5-Windows-Releases/releases/" target="_blank" rel="noreferrer">Nabu</a></li><li>For Oneplus 7TP/7T, the repo is <a href="https://github.com/n00b69/woa-op7/releases/tag/Drivers" target="_blank" rel="noreferrer">Hotdog</a></li><li>For others, please refer to <a href="./../ReferenceTables/DeviceCodenameReferenceTable.html">Devices&#39; Codename Reference Table</a><br> and download the one named xxx.</li></ul></li><li><p>Let Your Device Enter <a href="./EnterUMS.html">usb mass storage mode</a>.</p><blockquote><p>Ideally situation is that you have applied windows to your disk just now and your phone is still in ums mode.</p></blockquote></li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li><p>Unzip the .zip files you just downloading into correct folders.</p><ul><li>An example: <ul><li>Extract Driver Pack into <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\</code></li><li>Extract DriverUpdater.exe to <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\DriverUpdater.exe</code></li><li>Extract Device Specific Driver Pack to <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\components\\QC8150\\Device\\&lt;device-codename&gt;\\</code></li></ul></li></ul></li><li><p>Open a terminal with admin permission, then change directory to <code>&lt;silicon-codename&gt;-Drivers\\</code>.</p><ul><li>An example in <code>cmd</code>: <ul><li><code>cd /d D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\</code></li></ul></li><li>An example in <code>powershell</code>: <ul><li><code>cd &#39;D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\&#39;</code></li></ul></li></ul></li><li><p>Install drivers with <code>DriverUpdater.exe</code></p><ul><li>For details about how to use, please execute <code>DriverUpdater.exe --help</code>.</li><li>An example (assume the Windows partition on your phone assigned to <code>F:</code> on your computer): <ul><li><code>.\\DriverUpdater.exe -p F: -d definitions\\Desktop\\ARM64\\Internal\\&lt;device-codename&gt;.txt -r .</code></li></ul></li></ul></li><li><p>Waiting for completion.</p><ul><li>A screenshot after installing driver successfully on QRD778. <img src="'+r+'"></li></ul></li><li><p>Eject disk in explorer, then you have successfully installed all the drivers!!</p></li></ol>',6)])])}const b=o(s,[["render",d]]);export{f as __pageData,b as default};
